DROP TABLE IF EXISTS `orders`;
CREATE TABLE `orders`  (
  `id` bigint UNSIGNED NOT NULL COMMENT '订单id',
  `userId` bigint NOT NULL COMMENT '用户id',
  `orderNo` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '订单号',
  `orderStatus` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '订单状态 0待支付 1已支付 2已关闭',
  `totalAmount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '订单总金额',
  `payAmount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '实付金额',
  `addressId` bigint UNSIGNED NOT NULL COMMENT '地址id',
  `receiverName` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '收货人',
  `receiverPhone` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '收货手机号',
  `province` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '省',
  `city` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '市',
  `district` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '区',
  `detailAddress` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '详细地址',
  `payTime` datetime NULL DEFAULT NULL COMMENT '支付时间',
  `closeTime` datetime NULL DEFAULT NULL COMMENT '关闭时间',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '订单备注',
  `createTime` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updateTime` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `isDelete` tinyint(1) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_orders_orderNo`(`orderNo` ASC) USING BTREE,
  INDEX `idx_orders_userId_status`(`userId` ASC, `orderStatus` ASC) USING BTREE,
  INDEX `idx_orders_addressId`(`addressId` ASC) USING BTREE,
  INDEX `idx_orders_createTime`(`createTime` ASC) USING BTREE,
  CONSTRAINT `fk_orders_address` FOREIGN KEY (`addressId`) REFERENCES `user_address` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_orders_user` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '订单表' ROW_FORMAT = Dynamic;

