-- ----------------------------
-- Table structure for user_product_preference
-- ----------------------------
DROP TABLE IF EXISTS `user_product_preference`;
CREATE TABLE `user_product_preference`  (
  `id` bigint UNSIGNED NOT NULL COMMENT '用户商品偏好id',
  `userId` bigint NOT NULL COMMENT '用户id',
  `productId` bigint UNSIGNED NOT NULL COMMENT '商品id',
  `viewCount` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '浏览次数',
  `favoriteScore` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '收藏权重分',
  `cartScore` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '加购权重分',
  `reviewScore` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '评论权重分',
  `preferenceScore` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '综合偏好分',
  `lastBehaviorTime` datetime NULL DEFAULT NULL COMMENT '最后一次行为时间',
  `createTime` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updateTime` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `isDelete` tinyint(1) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_product_preference_userId_productId`(`userId` ASC, `productId` ASC) USING BTREE,
  INDEX `idx_user_product_preference_userId_score`(`userId` ASC, `preferenceScore` ASC) USING BTREE,
  INDEX `idx_user_product_preference_productId_score`(`productId` ASC, `preferenceScore` ASC) USING BTREE,
  INDEX `idx_user_product_preference_lastBehaviorTime`(`lastBehaviorTime` ASC) USING BTREE,
  CONSTRAINT `fk_user_product_preference_product` FOREIGN KEY (`productId`) REFERENCES `product` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_user_product_preference_user` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户商品偏好汇总表' ROW_FORMAT = Dynamic;

