-- Records of user_product_preference
-- ----------------------------

-- ----------------------------
-- Table structure for user_recommendation
-- ----------------------------
DROP TABLE IF EXISTS `user_recommendation`;
CREATE TABLE `user_recommendation`  (
  `id` bigint UNSIGNED NOT NULL COMMENT '用户推荐结果id',
  `userId` bigint NOT NULL COMMENT '用户id',
  `productId` bigint UNSIGNED NOT NULL COMMENT '推荐商品id',
  `recommendScore` decimal(10, 4) NOT NULL DEFAULT 0.0000 COMMENT '推荐分数',
  `recommendReason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '推荐原因',
  `sourceVersion` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '结果版本',
  `rankNum` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '推荐排名',
  `expireTime` datetime NULL DEFAULT NULL COMMENT '过期时间',
  `createTime` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updateTime` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `isDelete` tinyint(1) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_recommendation_userId_productId_version`(`userId` ASC, `productId` ASC, `sourceVersion` ASC) USING BTREE,
  INDEX `idx_user_recommendation_userId_rankNum`(`userId` ASC, `rankNum` ASC) USING BTREE,
  INDEX `idx_user_recommendation_userId_score`(`userId` ASC, `recommendScore` ASC) USING BTREE,
  INDEX `idx_user_recommendation_sourceVersion`(`sourceVersion` ASC) USING BTREE,
  INDEX `idx_user_recommendation_expireTime`(`expireTime` ASC) USING BTREE,
  INDEX `fk_user_recommendation_product`(`productId` ASC) USING BTREE,
  CONSTRAINT `fk_user_recommendation_product` FOREIGN KEY (`productId`) REFERENCES `product` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_user_recommendation_user` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户推荐结果表' ROW_FORMAT = Dynamic;

